const agreements = $input.first().json.entries ?? [];
const agreement = agreements.find((entry) => entry.id) ?? {};

return [
  {
    json: {
      relationshipId: agreement.id ?? null,
      agreementName: agreement.name ?? null,
      clientBusinessName: agreement.client?.business?.name ?? null,
    },
  },
];

const root = $input.first().json;
const candidates = [
  ['entries', root.entries],
  ['data', root.data],
  ['invoices', root.invoices],
  ['items', root.items],
  ['results', root.results],
  ['root', Array.isArray(root) ? root : null],
].filter(([, value]) => Array.isArray(value));

const [arrayKey, invoices] = candidates[0] ?? ['none', []];
const sample = invoices.slice(0, 3);
const sampleFields = [...new Set(sample.flatMap((invoice) => Object.keys(invoice ?? {})))].sort();
const first = invoices[0] ?? {};
const invoiceId = first.id ?? first.invoiceId ?? first.invoice_id ?? null;

return [
  {
    json: {
      totalCount: root.totalCount ?? root.total_count ?? null,
      detectedArrayKey: arrayKey,
      invoiceCount: invoices.length,
      sampleFields,
      sample,
      invoiceId,
    },
  },
];

const detail = $input.first().json;
const arrays = [];

function walk(value, path = []) {
  if (Array.isArray(value)) {
    const pathText = path.join('.').toLowerCase();
    if (pathText.includes('line') || pathText.includes('item') || pathText.includes('service')) {
      arrays.push({ path: path.join('.'), count: value.length, sample: value.slice(0, 2) });
    }
    value.forEach((child, index) => walk(child, [...path, index]));
    return;
  }
  if (!value || typeof value !== 'object') return;
  for (const [key, child] of Object.entries(value)) {
    walk(child, [...path, key]);
  }
}

walk(detail);

return [
  {
    json: {
      rootFields: Object.keys(detail ?? {}).sort(),
      invoiceId: detail.id ?? detail.invoiceId ?? detail.invoice_id ?? null,
      invoiceNumber: detail.invoiceNumber ?? detail.invoice_number ?? detail.number ?? null,
      relationshipId: detail.relationshipId ?? detail.relationship?.id ?? detail.agreementId ?? null,
      totalAmount: detail.totalAmount ?? detail.total ?? detail.amount ?? null,
      status: detail.displayStatus ?? detail.status ?? null,
      lineItemArrays: arrays,
      rawSample: detail,
    },
  },
];
